import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{t as i}from"./chunks/installer-screen.Db0E_BrK.js";import{t as a}from"./chunks/updating-fabric.1C0PZ95m.js";const o=JSON.parse(`{"title":"Atualizando o Fabric no Windows","description":"Tutorial passo a passo de como atualizar o Fabric no seu Windows.","frontmatter":{"title":"Atualizando o Fabric no Windows","description":"Tutorial passo a passo de como atualizar o Fabric no seu Windows.","authors":["IMB11","modmuss50"],"next":false,"files":[]},"headers":[],"relativePath":"pt_br/players/updating-fabric/windows.md","filePath":"translated/pt_br/players/updating-fabric/windows.md","lastUpdated":1772272927000}`);var s={name:`pt_br/players/updating-fabric/windows.md`};function c(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Atualizando o Fabric no Windows <a class="header-anchor" href="#h1" aria-label="Permalink to “Atualizando o Fabric no Windows”">​</a></h1><h2 id="1-download-the-fabric-installer" tabindex="-1">1. Baixar o instalador do Fabric <a class="header-anchor" href="#1-download-the-fabric-installer" aria-label="Permalink to “1. Baixar o instalador do Fabric”">​</a></h2><p>Baixe a versão do <code>.exe</code> do instalador do Fabric direto do <a href="https://fabricmc.net/use/" target="_blank" rel="noreferrer">Site do Fabric</a>, clicando em <code>Download for Windows</code>.</p><div class="tip custom-block"><p class="custom-block-title custom-block-title-default">TIP</p><p>Essa versão <code>.exe</code> para Windows não requer que o Java esteja instalado, porque ela já usa o Pacote Java dentro do Iniciador Oficial do Minecraft.</p></div><h2 id="2-run-the-fabric-installer" tabindex="-1">2. Execute o Instalador do Fabric <a class="header-anchor" href="#2-run-the-fabric-installer" aria-label="Permalink to “2. Execute o Instalador do Fabric”">​</a></h2><p>Feche o Minecraft e o Iniciador antes de executar o Instalador.</p><p>Assim que você abrir o instalador, você deveria ver uma tela como essa:</p><p><img src="/assets/players/installing-fabric/installer-screen.png" alt="O instalador do Fabric com &quot;Install&quot; destacado" loading="lazy"></p><p>Tenha certeza de que a versão mais atual do jogo e do Loader estão corretos, então clique em &#39;Instalar&#39; para atualizar o Fabric.</p><div class="warning custom-block"><p class="custom-block-title">IMPORTANTE</p><p>Certifique-se de desmarcar &#39;Criar Perfil&#39; enquanto estiver executando o instalador!</p></div><h2 id="3-update-launcher-profile" tabindex="-1">3. Atualize o Perfil no Minecraft Launcher <a class="header-anchor" href="#3-update-launcher-profile" aria-label="Permalink to “3. Atualize o Perfil no Minecraft Launcher”">​</a></h2><p>Uma vez que a instalação esteja completa, abra o Minecraft Launcher. Então, vá até à aba de &#39;Instalações&#39;. Encontre o seu perfil do Fabric e abra sua tela de edição:</p><p><img src="/assets/players/updating-fabric.png" alt="Atualizando a versão do Fabric Loader no Minecraft Launcher" loading="lazy"></p><p>Substitua a versão com a nova versão do Fabric Loader que você acabou de instalar, e aperte <code>Salvar</code>.</p><h2 id="4-you-re-done" tabindex="-1">4. Tudo Pronto! <a class="header-anchor" href="#4-you-re-done" aria-label="Permalink to “4. Tudo Pronto!”">​</a></h2><p>Uma vez que você completou os passos acima, você pode voltar para a aba &#39;Jogar&#39;, selecionar o perfil do Fabric através do menu suspenso no canto inferior esquerdo e clicar em jogar!</p><p>Se você encontrar algum problema enquanto segue esse guia, você pode pedir por ajuda no [Discord do Fabric] (<a href="https://discord.fabricmc.net/" target="_blank" rel="noreferrer">https://discord.fabricmc.net/</a>) no canal &#39;#player-support&#39;.</p>`,17)]])}var l=r(s,[[`render`,c]]);export{o as __pageData,l as default};